    Schedules approved tasks on Google Calendar.

    Reads:
        state["scored_tasks"], state["approval_sent"], state["auto_approved"]

    Writes:
        state["scheduled_tasks"] — tasks successfully booked this run.

    Side effects:
        Google Calendar events; task_store updates; Slack warnings if unschedulable.

    Schedules any task in the store (via scored_tasks) with status \"approved\"
    and no calendar_event_id — including tasks approved via Slack between runs.
    """
    try:
        scored = state.get("scored_tasks") or []
        if not isinstance(scored, list):
            scored = []

        scheduled_tasks: list[dict[str, Any]] = []
        err_list: list[str] = list(state.get("errors") or [])

        for task in scored:
            if not isinstance(task, dict):
                continue
            tid = str(task.get("id", ""))
            if not tid:
                continue

            fresh = get_task(tid) or task
            status = str(fresh.get("status", ""))
            if status != "approved":
                continue
            if fresh.get("calendar_event_id"):
                continue

            created = find_and_book_slot(fresh)
            if created:
                updated = get_task(tid) or fresh
                scheduled_tasks.append(updated)
            elif str((get_task(tid) or {}).get("status", "")) == "unschedulable":
                updated = get_task(tid)
                if updated:
                    scheduled_tasks.append(updated)

        print(f"[M5] Booked {len([t for t in scheduled_tasks if t.get('calendar_event_id')])} event(s)")
