def load_processed_gmail_ids() -> set[str]:
    """
    Gmail message IDs we have already sent through M2 (success).
    Used to avoid re-fetching stale UNREAD forever while still skipping duplicates.
    """
    try:
        if not _PROCESSED_GMAIL_PATH.is_file():
            return set()
        with open(_PROCESSED_GMAIL_PATH, "r", encoding="utf-8") as f:
            data = json.load(f)
        if not isinstance(data, dict):
            return set()
        raw = data.get("message_ids")
        if not isinstance(raw, list):
            return set()
        return {str(x) for x in raw if x}
    except FileNotFoundError:
        return set()
    except json.JSONDecodeError as e:
        print(f"[ERROR][FileStore] Corrupt JSON at {_PROCESSED_GMAIL_PATH}: {e}")
        return set()
    except Exception as e:
        print(f"[ERROR][FileStore] load_processed_gmail_ids failed: {e}")
        return set()


def mark_gmail_message_processed(message_id: str) -> None:
    """
    Record that message_id completed M2 so get_unread_since can drop stale duplicates.

    Does not raise. Skips empty ids.
    """
    mid = (message_id or "").strip()
    if not mid:
        return
    try:
        ids_list: list[str] = []
        if _PROCESSED_GMAIL_PATH.is_file():
            with open(_PROCESSED_GMAIL_PATH, "r", encoding="utf-8") as f:
                data = json.load(f)
            if isinstance(data, dict):
                prev = data.get("message_ids")
                if isinstance(prev, list):
                    ids_list = [str(x) for x in prev if x]
        if mid in ids_list:
            return
        ids_list.append(mid)
        if len(ids_list) > _MAX_PROCESSED_GMAIL_IDS:
            ids_list = ids_list[-_MAX_PROCESSED_GMAIL_IDS :]
        _atomic_write_json(_PROCESSED_GMAIL_PATH, {"message_ids": ids_list})
    except Exception as e:
        print(f"[ERROR][FileStore] mark_gmail_message_processed failed: {e}")

